const KEYWORDS = ['automation', 'automat', 'rpa', 'robotic process', 'process automation', 'workflow automation', 'low-code', 'no-code', 'machine learning', 'deep learning', 'neural network', 'artificial intelligence', 'ai engineer', 'ai developer', 'ai specialist', 'ai researcher', 'ai architect', 'llm', 'large language model', 'generative ai', 'genai', 'gen-ai', 'prompt engineer', 'vector search', 'rag ', 'künstliche intelligenz', 'ki engineer', 'ki developer', 'ki-', ' ki ', 'maschinelles lernen', 'automatisierung', 'mlops', 'dataops', 'data engineer', 'data pipeline', 'etl', 'n8n', 'zapier', 'airflow', 'prefect', 'dagster', 'make.com', 'integration engineer', 'integration developer', 'devops', 'platform engineer', 'process mining'];
const EXCLUDE_TITLE = ['senior ', 'sr. ', 'sr ', 'staff engineer', 'principal ', 'lead engineer', 'tech lead', 'engineering lead', 'head of', 'director', 'vp ', 'vice president', 'account executive', 'account manager', 'sales manager', 'marketing manager', 'product marketing'];
const EXP_REGEX = new RegExp('\\b([5-9]|\\d{2})\\+?\\s*(?:years?|jahre?)(?:\\s+of)?\\s*(?:experience|erfahrung|berufserfahrung)', 'i');

return $input.all().filter(item => {
  const job = item.json;
  const title = (job.title || '').toLowerCase();
  const fullText = [title, (job.departments || ''), (job.content || '')].join(' ').toLowerCase();

  // Discard senior/lead/head/director titles
  if (EXCLUDE_TITLE.some(ex => title.includes(ex))) return false;
  // Discard postings requiring 5+ years of experience
  if (EXP_REGEX.test(fullText)) return false;
  // Keep only AI/automation-relevant roles
  return KEYWORDS.some(kw => fullText.includes(kw));
});

const now = new Date().toISOString();
return $input.all().map(item => {
  const j = item.json;
  return { json: {
    normalized_input: {
      input_source: 'scraped',
      source_detail: j._source || 'corporate_api',
      email_account_id: null,
      email_address: null,
      email_provider: null,
      subject: '[JOB POSTING] ' + (j.title || '') + ' @ ' + (j._company || ''),
      date: now,
      raw_text: [
        '=== JOB POSTING FROM CORPORATE CAREER PAGE ===',
        'Source: ' + (j._source || 'corporate_api'),
        'Company: ' + (j._company || ''),
        'Position: ' + (j.title || ''),
        'Location: ' + (j.location || ''),
        'Department: ' + (j.departments || ''),
        'URL: ' + (j.url || ''),
        '',
        '=== JOB DESCRIPTION ===',
        j.content || ''
      ].join('\n').substring(0, 8000),
      raw_meta: {
        company: j._company || null,
        company_slug: j._company_slug || null,
        job_url: j.url || null,
        published_at: j.published_at || null,
        source: j._source || null
      }
    }
  } };
});

